	UBFX $8, R1, $8, R16
	BFI  $8, R16, $8, R0
	LSL  R1, R10, R10
	ADD  R1, R11, R15
	BFI  $0, R15, $8, R11

	// val3 := br3.peekTopBits(peekBits)
	MOVD R10, R12
	MOVD R6, R1
	LSR  R1, R12, R12

	// v3 := table[val0&mask]
	ADD   R12<<1, R8, R15
	MOVHU (R15), R1

	// br3.advance(uint8(v3.entry)
	UBFX $8, R1, $8, R16
	BFI  $0, R16, $8, R0
	LSL  R1, R10, R10
	ADD  R1, R11, R15
	BFI  $0, R15, $8, R11
	REVW R0, R0

	// these four writes get coalesced
	// out[id * dstEvery + 0] = uint8(v0.entry >> 8)
	// out[id * dstEvery + 1] = uint8(v1.entry >> 8)
	// out[id * dstEvery + 3] = uint8(v2.entry >> 8)
	// out[id * dstEvery + 4] = uint8(v3.entry >> 8)
	ADD  R7<<1, R7, R1
	ADD  R1, R3, R15
	MOVW R0, (R15)

	// update the bitreader structure
	MOVD R10, 176(R9)
	MOVB R11, 184(R9)
	ADD  $0x04, R3, R3
	AND  $0xff, R2, R15
	AND  $0xff, R2, R16
	TST  R16, R15
	BEQ  main_loop
	MOVD ctx+0(FP), R0
	MOVD 16(R0), R16
	SUB  R16, R3, R3
	LSL  $0x02, R3, R3
	MOVD R3, 40(R0)
	RET

// func decompress1x_main_loop_amd64(ctx *decompress1xContext)
TEXT ·decompress1x_main_loop_arm64(SB), $0-8
	MOVD  ctx+0(FP), R1
	MOVD  16(R1), R2
	MOVD  24(R1), R3
	CMP   $0x04, R3
	BLO   error_max_decoded_size_exceeded
	ADD   R3, R2, R3
	MOVD  (R1), R5
	MOVD  (R5), R7
	MOVD  24(R5), R8
	MOVD  32(R5), R9
	MOVBU 40(R5), R10
	MOVD  32(R1), R5
	MOVBU 8(R1), R6
	JMP   loop_condition

main_loop:
	// Check if we have room for 4 bytes in the output buffer
	ADD $4, R2, R1
	CMP R3, R1
	BGE error_max_decoded_size_exceeded

	// Decode 4 values
	CMP   $0x20, R10
	BLT   bitReader_fillFast_1_end
	SUB   $0x20, R10, R10
	SUB   $0x04, R8, R8
	ADD   R8, R7, R15
	MOVWU (R15), R11
	MOVD  R10, R1
	LSL   R1, R11, R11
	ORR   R11, R9, R9

bitReader_fillFast_1_end:
	MOVD  R6, R1
	MOVD  R9, R11
	LSR   R1, R11, R11
	ADD   R11<<1, R5, R15
	MOVHU (R15), R1
	UBFX  $8, R1, $8, R16
	BFI   $0, R16, $8, R0
	MOVBU R1, R1
	ADD   R1, R10, R10
	LSL   R1, R9, R9
	MOVD  R6, R1
	MOVD  R9, R11
	LSR   R1, R11, R11
	ADD   R11<<1, R5, R15
	MOVHU (R15), R1
	UBFX  $8, R1, $8, R16
	BFI   $8, R16, $8, R0
	MOVBU R1, R1
	ADD   R1, R10, R10
	LSL   R1, R9, R9
	REVW  R0, R0
	CMP   $0x20, R10
	BLT   bitReader_fillFast_2_end
	SUB   $0x20, R10, R10
	SUB   $0x04, R8, R8
	ADD   R8, R7, R15
	MOVWU (R15), R11
	MOVD  R10, R1
	LSL   R1, R11, R11
	ORR   R11, R9, R9

bitReader_fillFast_2_end:
	MOVD  R6, R1
	MOVD  R9, R11
	LSR   R1, R11, R11
	ADD   R11<<1, R5, R15
	MOVHU (R15), R1
	UBFX  $8, R1, $8, R16
	BFI   $8, R16, $8, R0
	MOVBU R1, R1
	ADD   R1, R10, R10
	LSL   R1, R9, R9
	MOVD  R6, R1
	MOVD  R9, R11
	LSR   R1, R11, R11
	ADD   R11<<1, R5, R15
	MOVHU (R15), R1
	UBFX  $8, R1, $8, R16
	BFI   $0, R16, $8, R0
	MOVBU R1, R1
	ADD   R1, R10, R10
	LSL   R1, R9, R9
	REVW  R0, R0

	// Store the decoded values
	MOVW R0, (R2)
	ADD  $0x04, R2, R2

loop_condition:
	CMP $0x08, R8
	BGE main_loop

	// Update ctx structure
	MOVD ctx+0(FP), R0
	MOVD 16(R0), R16
	SUB  R16, R2, R2
	MOVD R2, 40(R0)
	MOVD (R0), R0
	MOVD R8, 24(R0)
	MOVD R9, 32(R0)
	MOVB R10, 40(R0)
	RET

	// Report error
error_max_decoded_size_exceeded:
	MOVD ctx+0(FP), R0
	MOVD $-1, R1
	MOVD R1, 40(R0)
	RET

